    }

    public void ValidaConvEmptyStrToNull(ref DataRow dr)
    {
      if (dr != null)
      {
            if (dr["ID_BLOCO_INSC_ONLINE"] != null && string.IsNullOrEmpty(dr["ID_BLOCO_INSC_ONLINE"].ToString()))
              dr["ID_BLOCO_INSC_ONLINE"] = DBNull.Value;
            if (dr["ITEM"] != null && string.IsNullOrEmpty(dr["ITEM"].ToString()))
              dr["ITEM"] = DBNull.Value;
            if (dr["OBRIGATORIO"] != null && string.IsNullOrEmpty(dr["OBRIGATORIO"].ToString()))
              dr["OBRIGATORIO"] = DBNull.Value;
      }
    }

    public string ValidaCampos(DataRow dr)
    {
      if (dr != null)
      {

            if (dr["ID_BLOCO_INSC_ONLINE"] == null || string.IsNullOrEmpty(dr["ID_BLOCO_INSC_ONLINE"].ToString()))
            {
              return "Favor informar o Id_bloco_insc_online.";
            }

            if (dr["ID_BLOCO_INSC_ONLINE"] != null && !string.IsNullOrEmpty(dr["ID_BLOCO_INSC_ONLINE"].ToString()))
            {
              if ((Convert.ToDecimal(dr["ID_BLOCO_INSC_ONLINE"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ID_BLOCO_INSC_ONLINE"]).ToString("0.############").Split(',')[0].Length > 10) || (Convert.ToDecimal(dr["ID_BLOCO_INSC_ONLINE"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ID_BLOCO_INSC_ONLINE"]).ToString("0.############").Split(',')[1].Length > 0))
              {
                return "O Id_bloco_insc_online deve ser um valor inteiro com 10 dígitos no máximo.";
              }
            }

            if (dr["ITEM"] == null || string.IsNullOrEmpty(dr["ITEM"].ToString()))
            {
              return "Favor informar o Item.";
            }

            if (dr["ITEM"] != null && !string.IsNullOrEmpty(dr["ITEM"].ToString()))
            {
              if (dr["ITEM"].ToString().Length > 40)
              {
                return "O Item deve possuir no máximo 40 caracteres.";
              }
            }

            if (dr["OBRIGATORIO"] == null || string.IsNullOrEmpty(dr["OBRIGATORIO"].ToString()))
            {
              return "Favor informar o Obrigatorio.";
            }

            if (dr["OBRIGATORIO"] != null && !string.IsNullOrEmpty(dr["OBRIGATORIO"].ToString()))
            {
              if (dr["OBRIGATORIO"].ToString().Length > 1)
              {
                return "O Obrigatorio deve possuir no máximo 1 caractere.";
              }
            }
      }
      return "";
    }

    protected override string PreInsert(DataRow row, TConnectionWritable connection)
    {
      ValidaConvEmptyStrToNull(ref row);
      return ValidaCampos(row);
    }

    protected override string PreUpdate(DataRow row, TConnectionWritable connection)
    {
      ValidaConvEmptyStrToNull(ref row);
      return ValidaCampos(row);
    }

