              if ((Convert.ToDecimal(dr["ID_BLOCO_INSC_ITENS"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ID_BLOCO_INSC_ITENS"]).ToString("0.############").Split(',')[0].Length > 10) || (Convert.ToDecimal(dr["ID_BLOCO_INSC_ITENS"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ID_BLOCO_INSC_ITENS"]).ToString("0.############").Split(',')[1].Length > 0))
