      }



      Put(da, connection, dataRows);
    }

    public void ValidaConvEmptyStrToNull(ref DataRow dr)
    {
      if (dr != null)
      {
            if (dr["BLOCO"] != null && string.IsNullOrEmpty(dr["BLOCO"].ToString()))
              dr["BLOCO"] = DBNull.Value;
            if (dr["BLOCO_DESCRI"] != null && string.IsNullOrEmpty(dr["BLOCO_DESCRI"].ToString()))
              dr["BLOCO_DESCRI"] = DBNull.Value;
      }
    }

    public string ValidaCampos(DataRow dr)
    {
      if (dr != null)
      {

            if (dr["BLOCO"] == null || string.IsNullOrEmpty(dr["BLOCO"].ToString()))
            {
              return "Favor informar o Bloco.";
            }

            if (dr["BLOCO"] != null && !string.IsNullOrEmpty(dr["BLOCO"].ToString()))
            {
              if (dr["BLOCO"].ToString().Length > 100)
              {
                return "O Bloco deve possuir no máximo 100 caracteres.";
              }
            }

            if (dr["BLOCO_DESCRI"] == null || string.IsNullOrEmpty(dr["BLOCO_DESCRI"].ToString()))
            {
              return "Favor informar o Bloco_descri.";
            }

            if (dr["BLOCO_DESCRI"] != null && !string.IsNullOrEmpty(dr["BLOCO_DESCRI"].ToString()))
            {
              if (dr["BLOCO_DESCRI"].ToString().Length > 100)
              {
                return "O Bloco_descri deve possuir no máximo 100 caracteres.";
              }
            }
      }
      return "";
    }

    protected override string PreInsert(DataRow row, TConnectionWritable connection)
    {
      ValidaConvEmptyStrToNull(ref row);
      return ValidaCampos(row);
    }

    protected override string PreUpdate(DataRow row, TConnectionWritable connection)
    {
      ValidaConvEmptyStrToNull(ref row);
      return ValidaCampos(row);
    }

