    public string ValidaCampos(DataRow dr)
    {
      if (dr != null)
      {

            if (dr["CONCURSO"] == null || string.IsNullOrEmpty(dr["CONCURSO"].ToString()))
            {
              return "Favor informar o Concurso.";
            }

            if (dr["CONCURSO"] != null && !string.IsNullOrEmpty(dr["CONCURSO"].ToString()))
            {
              if (dr["CONCURSO"].ToString().Length > 20)
              {
                return "O Concurso deve possuir no máximo 20 caracteres.";
              }
            }

            if (dr["DESCRICAO"] != null && !string.IsNullOrEmpty(dr["DESCRICAO"].ToString()))
            {
              if (dr["DESCRICAO"].ToString().Length > 100)
              {
                return "O Descricao deve possuir no máximo 100 caracteres.";
              }
            }

            if (dr["STATUS"] == null || string.IsNullOrEmpty(dr["STATUS"].ToString()))
            {
              return "Favor informar o Status.";
            }

            if (dr["STATUS"] != null && !string.IsNullOrEmpty(dr["STATUS"].ToString()))
            {
              if (dr["STATUS"].ToString().Length > 15)
              {
                return "O Status deve possuir no máximo 15 caracteres.";
              }

              if (dr["STATUS"] != null && !string.IsNullOrEmpty(dr["STATUS"].ToString()))
              {
                List<object> lstSTATUS = new List<object>(new object[]{"Inativo", "Ativo"});
                if(!lstSTATUS.Contains(dr["STATUS"].ToString()))
                {
                  return "Os valores permitidos para o Status săo ''Inativo'' ou ''Ativo''.";
                }
              }
            }

            if (dr["NUM_MAX_OPCOES"] == null || string.IsNullOrEmpty(dr["NUM_MAX_OPCOES"].ToString()))
            {
              return "Favor informar o Num_max_opcoes.";
            }

            if (dr["NUM_MAX_OPCOES"] != null && !string.IsNullOrEmpty(dr["NUM_MAX_OPCOES"].ToString()))
            {
              if ((Convert.ToDecimal(dr["NUM_MAX_OPCOES"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["NUM_MAX_OPCOES"]).ToString("0.############").Split(',')[0].Length > 3) || (Convert.ToDecimal(dr["NUM_MAX_OPCOES"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["NUM_MAX_OPCOES"]).ToString("0.############").Split(',')[1].Length > 0))
              {
                return "O Num_max_opcoes deve ser um valor inteiro com 3 dígitos no máximo.";
              }
            }

            if (dr["ANO"] == null || string.IsNullOrEmpty(dr["ANO"].ToString()))
