    /// <param name="toLower">As colunas serăo devolvidas em minúsculas</param>
    /// <param name="tabPrincipal">Somente colunas da tabela principal</param>
    private static StringCollection FilterColumns(string[] columns, bool toLower, bool tabPrincipal) {
      StringCollection result = new StringCollection();

      if(columns != null)
        foreach(string column in columns) {
          string lower = column.ToLower();
          if(lower == "id_envio_email") { result.Add(toLower ? "id_envio_email" : column); continue; }
          if(lower == "pessoa") { result.Add(toLower ? "pessoa" : column); continue; }
          if(lower == "servidor") { result.Add(toLower ? "servidor" : column); continue; }
          if(lower == "servidor_porta") { result.Add(toLower ? "servidor_porta" : column); continue; }
          if(lower == "remetente") { result.Add(toLower ? "remetente" : column); continue; }
          if(lower == "remetente_nome") { result.Add(toLower ? "remetente_nome" : column); continue; }
          if(lower == "destinatario") { result.Add(toLower ? "destinatario" : column); continue; }
          if(lower == "destinatario_nome") { result.Add(toLower ? "destinatario_nome" : column); continue; }
          if(lower == "assunto") { result.Add(toLower ? "assunto" : column); continue; }
          if(lower == "mensagem") { result.Add(toLower ? "mensagem" : column); continue; }
          if(lower == "numero_tentativas") { result.Add(toLower ? "numero_tentativas" : column); continue; }
          if(lower == "status") { result.Add(toLower ? "status" : column); continue; }
          if(lower == "mensagem_erro") { result.Add(toLower ? "mensagem_erro" : column); continue; }
          if(!tabPrincipal) {
          }
        }

      if(result.Count == 0)
        if(tabPrincipal)
          result.AddRange(toLower
                          ? new string[] { "id_envio_email", "pessoa", "servidor", "servidor_porta", "remetente", 
                                           "remetente_nome", "destinatario", "destinatario_nome", "assunto", "mensagem", "numero_tentativas", 
                                           "status", "mensagem_erro" }
                          : new string[] { "ID_ENVIO_EMAIL", "PESSOA", "SERVIDOR", "SERVIDOR_PORTA", "REMETENTE", 
                                           "REMETENTE_NOME", "DESTINATARIO", "DESTINATARIO_NOME", "ASSUNTO", "MENSAGEM", "NUMERO_TENTATIVAS", 
                                           "STATUS", "MENSAGEM_ERRO" });
        else
          result.AddRange(toLower
                          ? new string[] { "id_envio_email", "pessoa", "servidor", "servidor_porta", "remetente", 
                                           "remetente_nome", "destinatario", "destinatario_nome", "assunto", "mensagem", "numero_tentativas", 
                                           "status", "mensagem_erro" }
                          : new string[] { "ID_ENVIO_EMAIL", "PESSOA", "SERVIDOR", "SERVIDOR_PORTA", "REMETENTE", 
                                           "REMETENTE_NOME", "DESTINATARIO", "DESTINATARIO_NOME", "ASSUNTO", "MENSAGEM", "NUMERO_TENTATIVAS", 
                                           "STATUS", "MENSAGEM_ERRO" });

      return result;
    }


