    public string ValidaCampos(DataRow dr)
    {
      if (dr != null)
      {

            if (dr["PESSOA"] == null || string.IsNullOrEmpty(dr["PESSOA"].ToString()))
            {
              return "Favor informar o Pessoa.";
            }

            if (dr["PESSOA"] != null && !string.IsNullOrEmpty(dr["PESSOA"].ToString()))
            {
              if ((Convert.ToDecimal(dr["PESSOA"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["PESSOA"]).ToString("0.############").Split(',')[0].Length > 10) || (Convert.ToDecimal(dr["PESSOA"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["PESSOA"]).ToString("0.############").Split(',')[1].Length > 0))
              {
                return "O Pessoa deve ser um valor inteiro com 10 dígitos no máximo.";
              }
            }

            if (dr["SERVIDOR"] == null || string.IsNullOrEmpty(dr["SERVIDOR"].ToString()))
            {
              return "Favor informar o Servidor.";
            }

            if (dr["SERVIDOR"] != null && !string.IsNullOrEmpty(dr["SERVIDOR"].ToString()))
            {
              if (dr["SERVIDOR"].ToString().Length > 50)
              {
                return "O Servidor deve possuir no máximo 50 caracteres.";
              }
            }

            if (dr["SERVIDOR_PORTA"] == null || string.IsNullOrEmpty(dr["SERVIDOR_PORTA"].ToString()))
            {
              return "Favor informar o Servidor_porta.";
            }

            if (dr["SERVIDOR_PORTA"] != null && !string.IsNullOrEmpty(dr["SERVIDOR_PORTA"].ToString()))
            {
              if (dr["SERVIDOR_PORTA"].ToString().Length > 50)
              {
                return "O Servidor_porta deve possuir no máximo 50 caracteres.";
              }
            }

            if (dr["REMETENTE"] == null || string.IsNullOrEmpty(dr["REMETENTE"].ToString()))
            {
              return "Favor informar o Remetente.";
            }

            if (dr["REMETENTE"] != null && !string.IsNullOrEmpty(dr["REMETENTE"].ToString()))
            {
              if (dr["REMETENTE"].ToString().Length > 50)
              {
                return "O Remetente deve possuir no máximo 50 caracteres.";
              }
            }

            if (dr["REMETENTE_NOME"] == null || string.IsNullOrEmpty(dr["REMETENTE_NOME"].ToString()))
            {
              return "Favor informar o Remetente_nome.";
            }

            if (dr["REMETENTE_NOME"] != null && !string.IsNullOrEmpty(dr["REMETENTE_NOME"].ToString()))
            {
              if (dr["REMETENTE_NOME"].ToString().Length > 50)
              {
                return "O Remetente_nome deve possuir no máximo 50 caracteres.";
              }
            }

            if (dr["DESTINATARIO"] == null || string.IsNullOrEmpty(dr["DESTINATARIO"].ToString()))
            {
              return "Favor informar o Destinatario.";
            }

            if (dr["DESTINATARIO"] != null && !string.IsNullOrEmpty(dr["DESTINATARIO"].ToString()))
            {
              if (dr["DESTINATARIO"].ToString().Length > 50)
              {
                return "O Destinatario deve possuir no máximo 50 caracteres.";
              }
            }

            if (dr["DESTINATARIO_NOME"] == null || string.IsNullOrEmpty(dr["DESTINATARIO_NOME"].ToString()))
