      }



      Put(da, connection, dataRows);
    }

    public void ValidaConvEmptyStrToNull(ref DataRow dr)
    {
      if (dr != null)
      {
            if (dr["FAIXA_EMPREGADOS"] != null && string.IsNullOrEmpty(dr["FAIXA_EMPREGADOS"].ToString()))
              dr["FAIXA_EMPREGADOS"] = DBNull.Value;
            if (dr["INICIO_FAIXA"] != null && string.IsNullOrEmpty(dr["INICIO_FAIXA"].ToString()))
              dr["INICIO_FAIXA"] = DBNull.Value;
            if (dr["FIM_FAIXA"] != null && string.IsNullOrEmpty(dr["FIM_FAIXA"].ToString()))
              dr["FIM_FAIXA"] = DBNull.Value;
      }
    }

    public string ValidaCampos(DataRow dr)
    {
      if (dr != null)
      {

            if (dr["FAIXA_EMPREGADOS"] == null || string.IsNullOrEmpty(dr["FAIXA_EMPREGADOS"].ToString()))
            {
              return "Favor informar o Faixa_empregados.";
            }

            if (dr["FAIXA_EMPREGADOS"] != null && !string.IsNullOrEmpty(dr["FAIXA_EMPREGADOS"].ToString()))
            {
              if (dr["FAIXA_EMPREGADOS"].ToString().Length > 20)
              {
                return "O Faixa_empregados deve possuir no máximo 20 caracteres.";
              }
            }

            if (dr["INICIO_FAIXA"] == null || string.IsNullOrEmpty(dr["INICIO_FAIXA"].ToString()))
            {
              return "Favor informar o Inicio_faixa.";
            }

            if (dr["INICIO_FAIXA"] != null && !string.IsNullOrEmpty(dr["INICIO_FAIXA"].ToString()))
            {
              if ((Convert.ToDecimal(dr["INICIO_FAIXA"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["INICIO_FAIXA"]).ToString("0.############").Split(',')[0].Length > 10) || (Convert.ToDecimal(dr["INICIO_FAIXA"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["INICIO_FAIXA"]).ToString("0.############").Split(',')[1].Length > 0))
              {
                return "O Inicio_faixa deve ser um valor inteiro com 10 dígitos no máximo.";
              }
            }

            if (dr["FIM_FAIXA"] == null || string.IsNullOrEmpty(dr["FIM_FAIXA"].ToString()))
            {
              return "Favor informar o Fim_faixa.";
            }

            if (dr["FIM_FAIXA"] != null && !string.IsNullOrEmpty(dr["FIM_FAIXA"].ToString()))
            {
              if ((Convert.ToDecimal(dr["FIM_FAIXA"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["FIM_FAIXA"]).ToString("0.############").Split(',')[0].Length > 10) || (Convert.ToDecimal(dr["FIM_FAIXA"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["FIM_FAIXA"]).ToString("0.############").Split(',')[1].Length > 0))
              {
                return "O Fim_faixa deve ser um valor inteiro com 10 dígitos no máximo.";
              }
            }
      }
      return "";
    }

    protected override string PreInsert(DataRow row, TConnectionWritable connection)
    {
      ValidaConvEmptyStrToNull(ref row);
      return ValidaCampos(row);
    }

    protected override string PreUpdate(DataRow row, TConnectionWritable connection)
    {
