    public void ValidaConvEmptyStrToNull(ref DataRow dr)
    {
      if (dr != null)
      {
            if (dr["FAIXA_SALARIAL"] != null && string.IsNullOrEmpty(dr["FAIXA_SALARIAL"].ToString()))
              dr["FAIXA_SALARIAL"] = DBNull.Value;
            if (dr["INICIO_FAIXA"] != null && string.IsNullOrEmpty(dr["INICIO_FAIXA"].ToString()))
              dr["INICIO_FAIXA"] = DBNull.Value;
            if (dr["FIM_FAIXA"] != null && string.IsNullOrEmpty(dr["FIM_FAIXA"].ToString()))
              dr["FIM_FAIXA"] = DBNull.Value;
      }
    }

    public string ValidaCampos(DataRow dr)
    {
      if (dr != null)
      {

            if (dr["FAIXA_SALARIAL"] == null || string.IsNullOrEmpty(dr["FAIXA_SALARIAL"].ToString()))
            {
              return "Favor informar o Faixa_salarial.";
            }

            if (dr["FAIXA_SALARIAL"] != null && !string.IsNullOrEmpty(dr["FAIXA_SALARIAL"].ToString()))
            {
              if (dr["FAIXA_SALARIAL"].ToString().Length > 20)
              {
                return "O Faixa_salarial deve possuir no máximo 20 caracteres.";
              }
            }

            if (dr["INICIO_FAIXA"] == null || string.IsNullOrEmpty(dr["INICIO_FAIXA"].ToString()))
            {
              return "Favor informar o Inicio_faixa.";
            }

            if (dr["INICIO_FAIXA"] != null && !string.IsNullOrEmpty(dr["INICIO_FAIXA"].ToString()))
            {
              if ((Convert.ToDecimal(dr["INICIO_FAIXA"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["INICIO_FAIXA"]).ToString("0.############").Split(',')[0].Length > 8) || (Convert.ToDecimal(dr["INICIO_FAIXA"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["INICIO_FAIXA"]).ToString("0.############").Split(',')[1].Length > 2))
              {
                return "O Inicio_faixa deve ser um valor numérico com, no máximo, 8 dígitos na parte inteira e 2 casas decimal.";
              }
            }

            if (dr["FIM_FAIXA"] == null || string.IsNullOrEmpty(dr["FIM_FAIXA"].ToString()))
            {
              return "Favor informar o Fim_faixa.";
            }

            if (dr["FIM_FAIXA"] != null && !string.IsNullOrEmpty(dr["FIM_FAIXA"].ToString()))
            {
              if ((Convert.ToDecimal(dr["FIM_FAIXA"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["FIM_FAIXA"]).ToString("0.############").Split(',')[0].Length > 8) || (Convert.ToDecimal(dr["FIM_FAIXA"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["FIM_FAIXA"]).ToString("0.############").Split(',')[1].Length > 2))
              {
                return "O Fim_faixa deve ser um valor numérico com, no máximo, 8 dígitos na parte inteira e 2 casas decimal.";
              }
            }
      }
      return "";
    }

    protected override string PreInsert(DataRow row, TConnectionWritable connection)
    {
      ValidaConvEmptyStrToNull(ref row);
      return ValidaCampos(row);
