          if(lower == "exibe_item") { result.Add(toLower ? "exibe_item" : column); continue; }
          if(lower == "pagina_web") { result.Add(toLower ? "pagina_web" : column); continue; }
          if(lower == "padrao") { result.Add(toLower ? "padrao" : column); continue; }
          if(lower == "id_campos_insc_padrao") { result.Add(toLower ? "id_campos_insc_padrao" : column); continue; }
          if(!tabPrincipal) {
          }
        }

      if(result.Count == 0)
        if(tabPrincipal)
          result.AddRange(toLower
                          ? new string[] { "id_inf_gerais_insc_on_line", "oferta_de_curso", "exibe_item", "pagina_web", 
                                           "padrao", "id_campos_insc_padrao" }
                          : new string[] { "ID_INF_GERAIS_INSC_ON_LINE", "OFERTA_DE_CURSO", "EXIBE_ITEM", "PAGINA_WEB", 
                                           "PADRAO", "ID_CAMPOS_INSC_PADRAO" });
        else
          result.AddRange(toLower
                          ? new string[] { "id_inf_gerais_insc_on_line", "oferta_de_curso", "exibe_item", "pagina_web", 
                                           "padrao", "id_campos_insc_padrao" }
                          : new string[] { "ID_INF_GERAIS_INSC_ON_LINE", "OFERTA_DE_CURSO", "EXIBE_ITEM", "PAGINA_WEB", 
                                           "PADRAO", "ID_CAMPOS_INSC_PADRAO" });

      return result;
    }


