      Put(da, connection, dataRows);
    }

    public void ValidaConvEmptyStrToNull(ref DataRow dr)
    {
      if (dr != null)
      {
            if (dr["OFERTA_DE_CURSO"] != null && string.IsNullOrEmpty(dr["OFERTA_DE_CURSO"].ToString()))
              dr["OFERTA_DE_CURSO"] = DBNull.Value;
            if (dr["EXIBE_ITEM"] != null && string.IsNullOrEmpty(dr["EXIBE_ITEM"].ToString()))
              dr["EXIBE_ITEM"] = DBNull.Value;
            if (dr["PAGINA_WEB"] != null && string.IsNullOrEmpty(dr["PAGINA_WEB"].ToString()))
              dr["PAGINA_WEB"] = DBNull.Value;
            if (dr["PADRAO"] != null && string.IsNullOrEmpty(dr["PADRAO"].ToString()))
              dr["PADRAO"] = DBNull.Value;
            if (dr["ID_CAMPOS_INSC_PADRAO"] != null && string.IsNullOrEmpty(dr["ID_CAMPOS_INSC_PADRAO"].ToString()))
              dr["ID_CAMPOS_INSC_PADRAO"] = DBNull.Value;
      }
    }

    public string ValidaCampos(DataRow dr)
    {
      if (dr != null)
      {

            if (dr["OFERTA_DE_CURSO"] == null || string.IsNullOrEmpty(dr["OFERTA_DE_CURSO"].ToString()))
            {
              return "Favor informar o Oferta_de_curso.";
            }

            if (dr["OFERTA_DE_CURSO"] != null && !string.IsNullOrEmpty(dr["OFERTA_DE_CURSO"].ToString()))
            {
              if ((Convert.ToDecimal(dr["OFERTA_DE_CURSO"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["OFERTA_DE_CURSO"]).ToString("0.############").Split(',')[0].Length > 10) || (Convert.ToDecimal(dr["OFERTA_DE_CURSO"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["OFERTA_DE_CURSO"]).ToString("0.############").Split(',')[1].Length > 0))
              {
                return "O Oferta_de_curso deve ser um valor inteiro com 10 dígitos no máximo.";
              }
            }

            if (dr["EXIBE_ITEM"] == null || string.IsNullOrEmpty(dr["EXIBE_ITEM"].ToString()))
            {
              return "Favor informar o Exibe_item.";
            }

            if (dr["EXIBE_ITEM"] != null && !string.IsNullOrEmpty(dr["EXIBE_ITEM"].ToString()))
            {
              if (dr["EXIBE_ITEM"].ToString().Length > 1)
              {
                return "O Exibe_item deve possuir no máximo 1 caractere.";
              }
            }

            if (dr["PAGINA_WEB"] != null && !string.IsNullOrEmpty(dr["PAGINA_WEB"].ToString()))
            {
              if (dr["PAGINA_WEB"].ToString().Length > 100)
              {
                return "O Pagina_web deve possuir no máximo 100 caracteres.";
              }
            }

            if (dr["PADRAO"] != null && !string.IsNullOrEmpty(dr["PADRAO"].ToString()))
            {
              if (dr["PADRAO"].ToString().Length > 2000)
              {
                return "O Padrao deve possuir no máximo 2000 caracteres.";
              }
            }

            if (dr["ID_CAMPOS_INSC_PADRAO"] != null && !string.IsNullOrEmpty(dr["ID_CAMPOS_INSC_PADRAO"].ToString()))
            {
              if ((Convert.ToDecimal(dr["ID_CAMPOS_INSC_PADRAO"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ID_CAMPOS_INSC_PADRAO"]).ToString("0.############").Split(',')[0].Length > 10) || (Convert.ToDecimal(dr["ID_CAMPOS_INSC_PADRAO"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ID_CAMPOS_INSC_PADRAO"]).ToString("0.############").Split(',')[1].Length > 0))
              {
                return "O Id_campos_insc_padrao deve ser um valor inteiro com 10 dígitos no máximo.";
              }
            }
      }
      return "";
    }

    protected override string PreInsert(DataRow row, TConnectionWritable connection)
    {
      ValidaConvEmptyStrToNull(ref row);
      return ValidaCampos(row);
    }

    protected override string PreUpdate(DataRow row, TConnectionWritable connection)
    {
      ValidaConvEmptyStrToNull(ref row);
      return ValidaCampos(row);
    }

