      if (rowCountOnly)
      {
        #region RowCountOnly
        using(TCommand cm = cn.CreateCommand(select, whereValues)) 
        {
          try 
          {
            count = (int)(decimal)cm.ExecuteScalar();
          }
          catch(Exception exc)
          {
            throw new Exception(exc.Message + " " +
              "Select statement: [" + select + "], " +
              "Parameters: [" + StrLib.EnumerableToStr(whereValues) + "]");
          }
        }
        #endregion
      }
      else
      {
        #region Fill Datatable
        using(TCommand cm = cn.CreateCommand(select, whereValues)) {
          TDataAdapter da = new TDataAdapter(cm);
          try {
            DataSet ds = BaseDataSet;
            bool fakeds = false;
            if(ds == null) {
              fakeds = true;
              ds = new DataSet();
              ds.Tables.Add(this);
            }
            count = da.Fill(ds, startRecord, maxRecords, "ly_itens_aux");
            if(fakeds) ds.Tables.Remove(this);
          }
          catch(Exception exc) {
            throw new Exception(exc.Message + " " +
                                "Select statement: [" + select + "], " +
                                "Parameters: [" + StrLib.EnumerableToStr(whereValues) + "]");
          }
        }

        if(createPrimaryKey) SetPrimaryKey();

        // Cria os nomes (caption) nas colunas da tabela do DataSet
        // de acordo com o idioma informado no construtor da classe.
        foreach(DataColumn dataColumn in Columns) {
          TDataColumn c = dataColumn as TDataColumn;
          if(c != null && scColumns.Contains(c.ColumnName.ToLower()))
            c.ReadOnly = c.IsAux;
        }
        #endregion
      }

      return count;
    }

    public override sealed void Put(TConnectionWritable connection, DataRow[] dataRows) {
      if(connection == null) throw new ArgumentNullException();

      TDataAdapter da; {
        da = new TDataAdapter();
        da.TableMappings.Add("Table", "Ly_itens_aux");
        da.ContinueUpdateOnError = true;
        da.RowUpdating += new TDataRowUpdateEventHandler(da_RowUpdating);
        da.RowUpdated += new TDataRowUpdateEventHandler(da_RowUpdated);

        da.InsertCommand = CreateCommand(connection, CommandOperation.Insert);
        da.UpdateCommand = CreateCommand(connection, CommandOperation.Update);
        da.DeleteCommand = CreateCommand(connection, CommandOperation.Delete);
      }



      Put(da, connection, dataRows);
    }

    public void ValidaConvEmptyStrToNull(ref DataRow dr)
    {
      if (dr != null)
      {
            if (dr["SESSAO_ID"] != null && string.IsNullOrEmpty(dr["SESSAO_ID"].ToString()))
              dr["SESSAO_ID"] = DBNull.Value;
            if (dr["CHAVE"] != null && string.IsNullOrEmpty(dr["CHAVE"].ToString()))
              dr["CHAVE"] = DBNull.Value;
            if (dr["VALOR"] != null && string.IsNullOrEmpty(dr["VALOR"].ToString()))
              dr["VALOR"] = DBNull.Value;
            if (dr["DESCRICAO"] != null && string.IsNullOrEmpty(dr["DESCRICAO"].ToString()))
              dr["DESCRICAO"] = DBNull.Value;
            if (dr["COBRANCA"] != null && string.IsNullOrEmpty(dr["COBRANCA"].ToString()))
              dr["COBRANCA"] = DBNull.Value;
            if (dr["ITEMCOBRANCA"] != null && string.IsNullOrEmpty(dr["ITEMCOBRANCA"].ToString()))
              dr["ITEMCOBRANCA"] = DBNull.Value;
            if (dr["PARCELA"] != null && string.IsNullOrEmpty(dr["PARCELA"].ToString()))
              dr["PARCELA"] = DBNull.Value;
            if (dr["ACORDO"] != null && string.IsNullOrEmpty(dr["ACORDO"].ToString()))
              dr["ACORDO"] = DBNull.Value;
      }
    }

    public string ValidaCampos(DataRow dr)
    {
      if (dr != null)
      {

            if (dr["SESSAO_ID"] == null || string.IsNullOrEmpty(dr["SESSAO_ID"].ToString()))
            {
              return "Favor informar o Sessao_id.";
            }

            if (dr["SESSAO_ID"] != null && !string.IsNullOrEmpty(dr["SESSAO_ID"].ToString()))
            {
              if (dr["SESSAO_ID"].ToString().Length > 40)
              {
                return "O Sessao_id deve possuir no máximo 40 caracteres.";
              }
            }

            if (dr["CHAVE"] == null || string.IsNullOrEmpty(dr["CHAVE"].ToString()))
            {
              return "Favor informar o Chave.";
            }

            if (dr["CHAVE"] != null && !string.IsNullOrEmpty(dr["CHAVE"].ToString()))
            {
              if ((Convert.ToDecimal(dr["CHAVE"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["CHAVE"]).ToString("0.############").Split(',')[0].Length > 10) || (Convert.ToDecimal(dr["CHAVE"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["CHAVE"]).ToString("0.############").Split(',')[1].Length > 0))
              {
                return "O Chave deve ser um valor inteiro com 10 dígitos no máximo.";
              }
            }

            if (dr["VALOR"] != null && !string.IsNullOrEmpty(dr["VALOR"].ToString()))
            {
              if ((Convert.ToDecimal(dr["VALOR"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["VALOR"]).ToString("0.############").Split(',')[0].Length > 8) || (Convert.ToDecimal(dr["VALOR"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["VALOR"]).ToString("0.############").Split(',')[1].Length > 4))
              {
                return "O Valor deve ser um valor numérico com, no máximo, 8 dígitos na parte inteira e 4 casas decimal.";
              }
            }

            if (dr["DESCRICAO"] != null && !string.IsNullOrEmpty(dr["DESCRICAO"].ToString()))
            {
              if (dr["DESCRICAO"].ToString().Length > 100)
              {
                return "O Descricao deve possuir no máximo 100 caracteres.";
              }
            }

            if (dr["DT_VENC"] != null && dr["DT_VENC"].ToString() != "")
            {
              dr["DT_VENC"] = Convert.ToDateTime(dr["DT_VENC"]).ToString("dd/MM/yyyy HH:mm:ss");
            }

            if (dr["COBRANCA"] != null && !string.IsNullOrEmpty(dr["COBRANCA"].ToString()))
            {
              if ((Convert.ToDecimal(dr["COBRANCA"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["COBRANCA"]).ToString("0.############").Split(',')[0].Length > 10) || (Convert.ToDecimal(dr["COBRANCA"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["COBRANCA"]).ToString("0.############").Split(',')[1].Length > 0))
              {
                return "O Cobranca deve ser um valor inteiro com 10 dígitos no máximo.";
              }
            }

            if (dr["ITEMCOBRANCA"] != null && !string.IsNullOrEmpty(dr["ITEMCOBRANCA"].ToString()))
            {
              if ((Convert.ToDecimal(dr["ITEMCOBRANCA"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ITEMCOBRANCA"]).ToString("0.############").Split(',')[0].Length > 3) || (Convert.ToDecimal(dr["ITEMCOBRANCA"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ITEMCOBRANCA"]).ToString("0.############").Split(',')[1].Length > 0))
              {
                return "O Itemcobranca deve ser um valor inteiro com 3 dígitos no máximo.";
              }
            }

            if (dr["PARCELA"] != null && !string.IsNullOrEmpty(dr["PARCELA"].ToString()))
            {
              if ((Convert.ToDecimal(dr["PARCELA"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["PARCELA"]).ToString("0.############").Split(',')[0].Length > 10) || (Convert.ToDecimal(dr["PARCELA"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["PARCELA"]).ToString("0.############").Split(',')[1].Length > 0))
              {
                return "O Parcela deve ser um valor inteiro com 10 dígitos no máximo.";
              }
            }

            if (dr["ACORDO"] != null && !string.IsNullOrEmpty(dr["ACORDO"].ToString()))
            {
              if ((Convert.ToDecimal(dr["ACORDO"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ACORDO"]).ToString("0.############").Split(',')[0].Length > 10) || (Convert.ToDecimal(dr["ACORDO"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ACORDO"]).ToString("0.############").Split(',')[1].Length > 0))
              {
                return "O Acordo deve ser um valor inteiro com 10 dígitos no máximo.";
              }
            }
      }
      return "";
    }

