    /// <param name="toLower">As colunas serăo devolvidas em minúsculas</param>
    /// <param name="tabPrincipal">Somente colunas da tabela principal</param>
    private static StringCollection FilterColumns(string[] columns, bool toLower, bool tabPrincipal) {
      StringCollection result = new StringCollection();

      if(columns != null)
        foreach(string column in columns) {
          string lower = column.ToLower();
          if(lower == "curriculo_desc") { result.Add(toLower ? "curriculo_desc" : column); continue; }
          if(lower == "pessoa") { result.Add(toLower ? "pessoa" : column); continue; }
          if(lower == "documento_curriculo") { result.Add(toLower ? "documento_curriculo" : column); continue; }
          if(lower == "nome") { result.Add(toLower ? "nome" : column); continue; }
          if(lower == "extensao") { result.Add(toLower ? "extensao" : column); continue; }
          if(!tabPrincipal) {
          }
        }

      if(result.Count == 0)
        if(tabPrincipal)
          result.AddRange(toLower
                          ? new string[] { "curriculo_desc", "pessoa", "documento_curriculo", "nome", "extensao" }
                          : new string[] { "CURRICULO_DESC", "PESSOA", "DOCUMENTO_CURRICULO", "NOME", "EXTENSAO" });
        else
          result.AddRange(toLower
                          ? new string[] { "curriculo_desc", "pessoa", "documento_curriculo", "nome", "extensao" }
                          : new string[] { "CURRICULO_DESC", "PESSOA", "DOCUMENTO_CURRICULO", "NOME", "EXTENSAO" });

      return result;
    }


