    public override sealed int Get(TConnection connection,
                                   string[] columns,
                                   string where, DbObject[] whereValues,
                                   string order,
                                   int startRecord,
                                   int maxRecords,
                                   bool createPrimaryKey,
                                   bool getDeletedRecords,
                                   bool rowCountOnly) {
      if(where == null) throw new ArgumentNullException("where");
      if(order == null) throw new ArgumentNullException("order");
      TConnection cn = connection != null ? connection : Config.CreateConnection();
      bool sqlServer = cn.Rdbms == Rdbms.SQLServer;
      where = where.Trim();

      int count;

      StringCollection scColumns = FilterColumns(columns, true, false);

      #region Build Select
      ArrayList list = new ArrayList();
      list.AddRange(new string[] {
        "ly_oferta_curso.oferta_de_curso"
      });
      if(scColumns.Contains("id_sub_grupo_oferta")) list.Add("ly_oferta_curso.id_sub_grupo_oferta");
      if(scColumns.Contains("curso")) list.Add("ly_oferta_curso.curso");
      if(scColumns.Contains("turno")) list.Add("ly_oferta_curso.turno");
      if(scColumns.Contains("curriculo")) list.Add("ly_oferta_curso.curriculo");
      if(scColumns.Contains("ano_ingresso")) list.Add("ly_oferta_curso.ano_ingresso");
      if(scColumns.Contains("per_ingresso")) list.Add("ly_oferta_curso.per_ingresso");
      if(scColumns.Contains("dtini")) list.Add("ly_oferta_curso.dtini");
      if(scColumns.Contains("dtfim")) list.Add("ly_oferta_curso.dtfim");
      if(scColumns.Contains("descricao_abrev")) list.Add("ly_oferta_curso.descricao_abrev");
      if(scColumns.Contains("descricao_compl")) list.Add("ly_oferta_curso.descricao_compl");
      if(scColumns.Contains("concurso")) list.Add("ly_oferta_curso.concurso");
      if(scColumns.Contains("curso_ofertado")) list.Add("ly_oferta_curso.curso_ofertado");
      if(scColumns.Contains("area")) list.Add("ly_oferta_curso.area");
      if(scColumns.Contains("vagas")) list.Add("ly_oferta_curso.vagas");
      if(scColumns.Contains("min_grupo")) list.Add("ly_oferta_curso.min_grupo");
      if(scColumns.Contains("perc_ajuste_vagas")) list.Add("ly_oferta_curso.perc_ajuste_vagas");
      if(scColumns.Contains("tipo_proc_seletivo")) list.Add("ly_oferta_curso.tipo_proc_seletivo");
      if(scColumns.Contains("tipooferta")) list.Add("ly_oferta_curso.tipooferta");
      if(scColumns.Contains("ultima_chamada")) list.Add("ly_oferta_curso.ultima_chamada");
      if(scColumns.Contains("serie")) list.Add("ly_oferta_curso.serie");
      if(scColumns.Contains("vagas_remanesc")) list.Add("ly_oferta_curso.vagas_remanesc");
      if(scColumns.Contains("unidade_fisica")) list.Add("ly_oferta_curso.unidade_fisica");
      if(scColumns.Contains("exibe_grade")) list.Add("ly_oferta_curso.exibe_grade");
      if(scColumns.Contains("mensagem")) list.Add("ly_oferta_curso.mensagem");
      if(scColumns.Contains("max_resp_finan")) list.Add("ly_oferta_curso.max_resp_finan");
      if(scColumns.Contains("valor_inscricao")) list.Add("ly_oferta_curso.valor_inscricao");
      if(scColumns.Contains("faculdade_conveniada")) list.Add("ly_oferta_curso.faculdade_conveniada");
      if(scColumns.Contains("dtini_interesse")) list.Add("ly_oferta_curso.dtini_interesse");
      if(scColumns.Contains("dtfim_interesse")) list.Add("ly_oferta_curso.dtfim_interesse");
      if(scColumns.Contains("matric_todas_opcoes")) list.Add("ly_oferta_curso.matric_todas_opcoes");
      if(scColumns.Contains("nao_realiza_pre_matr")) list.Add("ly_oferta_curso.nao_realiza_pre_matr");
      if(scColumns.Contains("valor_a_vista_estimado")) list.Add("ly_oferta_curso.valor_a_vista_estimado");
      if(scColumns.Contains("senha")) list.Add("ly_oferta_curso.senha");
      string select,columnList,orderby;
      if (rowCountOnly)
      {
        columnList = "count(*)";
        orderby = "";
      }
      else
      {
        columnList = StrLib.EnumerableToStr(list, ", ");
        orderby = (order.Trim().Length == 0 ? string.Empty : " ORDER BY " + order);
      }
      select =
        "SELECT " + columnList + " " +
          "FROM ly_oferta_curso " +
          (where.Length == 0 ? string.Empty : " WHERE " + where) +
          orderby;

      #endregion
      if (rowCountOnly)
      {
        #region RowCountOnly
        using(TCommand cm = cn.CreateCommand(select, whereValues)) 
        {
          try 
          {
            count = (int)(decimal)cm.ExecuteScalar();
          }
          catch(Exception exc)
          {
            throw new Exception(exc.Message + " " +
              "Select statement: [" + select + "], " +
              "Parameters: [" + StrLib.EnumerableToStr(whereValues) + "]");
          }
        }
        #endregion
      }
      else
      {
        #region Fill Datatable
        using(TCommand cm = cn.CreateCommand(select, whereValues)) {
          TDataAdapter da = new TDataAdapter(cm);
          try {
            DataSet ds = BaseDataSet;
            bool fakeds = false;
            if(ds == null) {
              fakeds = true;
              ds = new DataSet();
              ds.Tables.Add(this);
            }
            count = da.Fill(ds, startRecord, maxRecords, "ly_oferta_curso");
            if(fakeds) ds.Tables.Remove(this);
          }
          catch(Exception exc) {
            throw new Exception(exc.Message + " " +
                                "Select statement: [" + select + "], " +
                                "Parameters: [" + StrLib.EnumerableToStr(whereValues) + "]");
          }
        }

        if(createPrimaryKey) SetPrimaryKey();

        // Cria os nomes (caption) nas colunas da tabela do DataSet
        // de acordo com o idioma informado no construtor da classe.
        foreach(DataColumn dataColumn in Columns) {
          TDataColumn c = dataColumn as TDataColumn;
          if(c != null && scColumns.Contains(c.ColumnName.ToLower()))
            c.ReadOnly = c.IsAux;
        }
        #endregion
      }

      return count;
    }

    public override sealed void Put(TConnectionWritable connection, DataRow[] dataRows) {
      if(connection == null) throw new ArgumentNullException();

      TDataAdapter da; {
        da = new TDataAdapter();
        da.TableMappings.Add("Table", "Ly_oferta_curso");
        da.ContinueUpdateOnError = true;
        da.RowUpdating += new TDataRowUpdateEventHandler(da_RowUpdating);
        da.RowUpdated += new TDataRowUpdateEventHandler(da_RowUpdated);

        da.InsertCommand = CreateCommand(connection, CommandOperation.Insert);
        da.UpdateCommand = CreateCommand(connection, CommandOperation.Update);
        da.DeleteCommand = CreateCommand(connection, CommandOperation.Delete);
      }



      Put(da, connection, dataRows);
    }

