    public string ValidaCampos(DataRow dr)
    {
      if (dr != null)
      {

            if (dr["ID_SUB_GRUPO_OFERTA"] == null || string.IsNullOrEmpty(dr["ID_SUB_GRUPO_OFERTA"].ToString()))
            {
              return "Favor informar o Id_sub_grupo_oferta.";
            }

            if (dr["ID_SUB_GRUPO_OFERTA"] != null && !string.IsNullOrEmpty(dr["ID_SUB_GRUPO_OFERTA"].ToString()))
            {
              if ((Convert.ToDecimal(dr["ID_SUB_GRUPO_OFERTA"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ID_SUB_GRUPO_OFERTA"]).ToString("0.############").Split(',')[0].Length > 10) || (Convert.ToDecimal(dr["ID_SUB_GRUPO_OFERTA"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ID_SUB_GRUPO_OFERTA"]).ToString("0.############").Split(',')[1].Length > 0))
              {
                return "O Id_sub_grupo_oferta deve ser um valor inteiro com 10 dígitos no máximo.";
              }
            }

            if (dr["CURSO"] == null || string.IsNullOrEmpty(dr["CURSO"].ToString()))
            {
              return "Favor informar o Curso.";
            }

            if (dr["CURSO"] != null && !string.IsNullOrEmpty(dr["CURSO"].ToString()))
            {
              if (dr["CURSO"].ToString().Length > 20)
              {
                return "O Curso deve possuir no máximo 20 caracteres.";
              }
            }

