              }
            }

            if (dr["MENSAGEM"] != null && !string.IsNullOrEmpty(dr["MENSAGEM"].ToString()))
            {
              if (dr["MENSAGEM"].ToString().Length > 100)
              {
                return "O Mensagem deve possuir no máximo 100 caracteres.";
              }
            }

            if (dr["MAX_RESP_FINAN"] != null && !string.IsNullOrEmpty(dr["MAX_RESP_FINAN"].ToString()))
            {
