            }

            if (dr["FACULDADE_CONVENIADA"] != null && !string.IsNullOrEmpty(dr["FACULDADE_CONVENIADA"].ToString()))
            {
              if (dr["FACULDADE_CONVENIADA"].ToString().Length > 20)
              {
                return "O Faculdade_conveniada deve possuir no máximo 20 caracteres.";
              }
            }

            if (dr["DTINI_INTERESSE"] != null && dr["DTINI_INTERESSE"].ToString() != "")
            {
              dr["DTINI_INTERESSE"] = Convert.ToDateTime(dr["DTINI_INTERESSE"]).ToString("dd/MM/yyyy HH:mm:ss");
