    /// <summary>
    /// Filtra o array de colunas retornando somente as colunas pertencentes ao DataTable.
    /// Devolve StringCollection para que seja possível utilizar o método Contains().
    /// </summary>
    /// <param name="toLower">As colunas serăo devolvidas em minúsculas</param>
    /// <param name="tabPrincipal">Somente colunas da tabela principal</param>
    private static StringCollection FilterColumns(string[] columns, bool toLower, bool tabPrincipal) {
      StringCollection result = new StringCollection();

      if(columns != null)
        foreach(string column in columns) {
          string lower = column.ToLower();
          if(lower == "id_oferta_curso_descr_arquivo") { result.Add(toLower ? "id_oferta_curso_descr_arquivo" : column); continue; }
          if(lower == "id_oferta_curso_descr") { result.Add(toLower ? "id_oferta_curso_descr" : column); continue; }
          if(lower == "documento") { result.Add(toLower ? "documento" : column); continue; }
          if(lower == "nome") { result.Add(toLower ? "nome" : column); continue; }
          if(lower == "extensao") { result.Add(toLower ? "extensao" : column); continue; }
          if(!tabPrincipal) {
          }
        }

      if(result.Count == 0)
        if(tabPrincipal)
          result.AddRange(toLower
                          ? new string[] { "id_oferta_curso_descr_arquivo", "id_oferta_curso_descr", "documento", 
                                           "nome", "extensao" }
                          : new string[] { "ID_OFERTA_CURSO_DESCR_ARQUIVO", "ID_OFERTA_CURSO_DESCR", "DOCUMENTO", 
                                           "NOME", "EXTENSAO" });
        else
          result.AddRange(toLower
                          ? new string[] { "id_oferta_curso_descr_arquivo", "id_oferta_curso_descr", "documento", 
                                           "nome", "extensao" }
                          : new string[] { "ID_OFERTA_CURSO_DESCR_ARQUIVO", "ID_OFERTA_CURSO_DESCR", "DOCUMENTO", 
                                           "NOME", "EXTENSAO" });

      return result;
    }


