    public void ValidaConvEmptyStrToNull(ref DataRow dr)
    {
      if (dr != null)
      {
            if (dr["ID_OFERTA_CURSO_DESCR"] != null && string.IsNullOrEmpty(dr["ID_OFERTA_CURSO_DESCR"].ToString()))
              dr["ID_OFERTA_CURSO_DESCR"] = DBNull.Value;
            if (dr["NOME"] != null && string.IsNullOrEmpty(dr["NOME"].ToString()))
              dr["NOME"] = DBNull.Value;
            if (dr["EXTENSAO"] != null && string.IsNullOrEmpty(dr["EXTENSAO"].ToString()))
              dr["EXTENSAO"] = DBNull.Value;
      }
    }

    public string ValidaCampos(DataRow dr)
    {
      if (dr != null)
      {

            if (dr["ID_OFERTA_CURSO_DESCR"] == null || string.IsNullOrEmpty(dr["ID_OFERTA_CURSO_DESCR"].ToString()))
            {
              return "Favor informar o Id_oferta_curso_descr.";
            }

            if (dr["ID_OFERTA_CURSO_DESCR"] != null && !string.IsNullOrEmpty(dr["ID_OFERTA_CURSO_DESCR"].ToString()))
            {
              if ((Convert.ToDecimal(dr["ID_OFERTA_CURSO_DESCR"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ID_OFERTA_CURSO_DESCR"]).ToString("0.############").Split(',')[0].Length > 10) || (Convert.ToDecimal(dr["ID_OFERTA_CURSO_DESCR"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ID_OFERTA_CURSO_DESCR"]).ToString("0.############").Split(',')[1].Length > 0))
              {
                return "O Id_oferta_curso_descr deve ser um valor inteiro com 10 dígitos no máximo.";
              }
            }

            if (dr["NOME"] == null || string.IsNullOrEmpty(dr["NOME"].ToString()))
            {
              return "Favor informar o Nome.";
            }

            if (dr["NOME"] != null && !string.IsNullOrEmpty(dr["NOME"].ToString()))
            {
              if (dr["NOME"].ToString().Length > 100)
              {
                return "O Nome deve possuir no máximo 100 caracteres.";
              }
            }

            if (dr["EXTENSAO"] == null || string.IsNullOrEmpty(dr["EXTENSAO"].ToString()))
            {
              return "Favor informar o Extensao.";
            }

            if (dr["EXTENSAO"] != null && !string.IsNullOrEmpty(dr["EXTENSAO"].ToString()))
            {
              if (dr["EXTENSAO"].ToString().Length > 10)
              {
                return "O Extensao deve possuir no máximo 10 caracteres.";
              }
            }
      }
      return "";
    }

    protected override string PreInsert(DataRow row, TConnectionWritable connection)
    {
      ValidaConvEmptyStrToNull(ref row);
      return ValidaCampos(row);
    }

    protected override string PreUpdate(DataRow row, TConnectionWritable connection)
    {
      ValidaConvEmptyStrToNull(ref row);
      return ValidaCampos(row);
    }

