    private static StringCollection FilterColumns(string[] columns, bool toLower, bool tabPrincipal) {
      StringCollection result = new StringCollection();

      if(columns != null)
        foreach(string column in columns) {
          string lower = column.ToLower();
          if(lower == "id_interesse") { result.Add(toLower ? "id_interesse" : column); continue; }
          if(lower == "oferta_de_curso") { result.Add(toLower ? "oferta_de_curso" : column); continue; }
          if(lower == "data") { result.Add(toLower ? "data" : column); continue; }
          if(lower == "nome") { result.Add(toLower ? "nome" : column); continue; }
          if(lower == "email") { result.Add(toLower ? "email" : column); continue; }
          if(lower == "fone") { result.Add(toLower ? "fone" : column); continue; }
          if(lower == "email_enviado") { result.Add(toLower ? "email_enviado" : column); continue; }
          if(!tabPrincipal) {
          }
        }

      if(result.Count == 0)
        if(tabPrincipal)
          result.AddRange(toLower
                          ? new string[] { "id_interesse", "oferta_de_curso", "data", "nome", "email", "fone", 
                                           "email_enviado" }
                          : new string[] { "ID_INTERESSE", "OFERTA_DE_CURSO", "DATA", "NOME", "EMAIL", "FONE", 
                                           "EMAIL_ENVIADO" });
        else
          result.AddRange(toLower
                          ? new string[] { "id_interesse", "oferta_de_curso", "data", "nome", "email", "fone", 
                                           "email_enviado" }
                          : new string[] { "ID_INTERESSE", "OFERTA_DE_CURSO", "DATA", "NOME", "EMAIL", "FONE", 
                                           "EMAIL_ENVIADO" });

      return result;
    }


