    public void ValidaConvEmptyStrToNull(ref DataRow dr)
    {
      if (dr != null)
      {
            if (dr["OFERTA_DE_CURSO"] != null && string.IsNullOrEmpty(dr["OFERTA_DE_CURSO"].ToString()))
              dr["OFERTA_DE_CURSO"] = DBNull.Value;
            if (dr["NOME"] != null && string.IsNullOrEmpty(dr["NOME"].ToString()))
              dr["NOME"] = DBNull.Value;
            if (dr["EMAIL"] != null && string.IsNullOrEmpty(dr["EMAIL"].ToString()))
              dr["EMAIL"] = DBNull.Value;
            if (dr["FONE"] != null && string.IsNullOrEmpty(dr["FONE"].ToString()))
              dr["FONE"] = DBNull.Value;
            if (dr["EMAIL_ENVIADO"] != null && string.IsNullOrEmpty(dr["EMAIL_ENVIADO"].ToString()))
              dr["EMAIL_ENVIADO"] = DBNull.Value;
      }
    }

    public string ValidaCampos(DataRow dr)
    {
      if (dr != null)
      {

            if (dr["OFERTA_DE_CURSO"] == null || string.IsNullOrEmpty(dr["OFERTA_DE_CURSO"].ToString()))
            {
              return "Favor informar o Oferta_de_curso.";
            }

            if (dr["OFERTA_DE_CURSO"] != null && !string.IsNullOrEmpty(dr["OFERTA_DE_CURSO"].ToString()))
            {
              if ((Convert.ToDecimal(dr["OFERTA_DE_CURSO"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["OFERTA_DE_CURSO"]).ToString("0.############").Split(',')[0].Length > 10) || (Convert.ToDecimal(dr["OFERTA_DE_CURSO"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["OFERTA_DE_CURSO"]).ToString("0.############").Split(',')[1].Length > 0))
              {
                return "O Oferta_de_curso deve ser um valor inteiro com 10 dígitos no máximo.";
              }
            }

            if (dr["DATA"] == null || string.IsNullOrEmpty(dr["DATA"].ToString()))
            {
              return "Favor informar o Data.";
            }

            if (dr["DATA"] != null && dr["DATA"].ToString() != "")
            {
              dr["DATA"] = Convert.ToDateTime(dr["DATA"]).ToString("dd/MM/yyyy HH:mm:ss");
            }

            if (dr["NOME"] == null || string.IsNullOrEmpty(dr["NOME"].ToString()))
            {
              return "Favor informar o Nome.";
            }

            if (dr["NOME"] != null && !string.IsNullOrEmpty(dr["NOME"].ToString()))
            {
              if (dr["NOME"].ToString().Length > 100)
              {
                return "O Nome deve possuir no máximo 100 caracteres.";
              }
            }

            if (dr["EMAIL"] == null || string.IsNullOrEmpty(dr["EMAIL"].ToString()))
            {
              return "Favor informar o Email.";
            }

            if (dr["EMAIL"] != null && !string.IsNullOrEmpty(dr["EMAIL"].ToString()))
            {
              if (dr["EMAIL"].ToString().Length > 100)
              {
                return "O Email deve possuir no máximo 100 caracteres.";
              }
            }

            if (dr["FONE"] != null && !string.IsNullOrEmpty(dr["FONE"].ToString()))
            {
              if (dr["FONE"].ToString().Length > 30)
              {
                return "O Fone deve possuir no máximo 30 caracteres.";
              }
            }

            if (dr["EMAIL_ENVIADO"] != null && !string.IsNullOrEmpty(dr["EMAIL_ENVIADO"].ToString()))
            {
              if (dr["EMAIL_ENVIADO"].ToString().Length > 1)
              {
                return "O Email_enviado deve possuir no máximo 1 caractere.";
              }
            }
      }
      return "";
    }

    protected override string PreInsert(DataRow row, TConnectionWritable connection)
    {
      ValidaConvEmptyStrToNull(ref row);
      return ValidaCampos(row);
    }

    protected override string PreUpdate(DataRow row, TConnectionWritable connection)
    {
      ValidaConvEmptyStrToNull(ref row);
      return ValidaCampos(row);
    }

