    public string ValidaCampos(DataRow dr)
    {
      if (dr != null)
      {

            if (dr["OFERTA_DE_CURSO"] == null || string.IsNullOrEmpty(dr["OFERTA_DE_CURSO"].ToString()))
            {
              return "Favor informar o Oferta_de_curso.";
            }

            if (dr["OFERTA_DE_CURSO"] != null && !string.IsNullOrEmpty(dr["OFERTA_DE_CURSO"].ToString()))
            {
              if ((Convert.ToDecimal(dr["OFERTA_DE_CURSO"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["OFERTA_DE_CURSO"]).ToString("0.############").Split(',')[0].Length > 10) || (Convert.ToDecimal(dr["OFERTA_DE_CURSO"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["OFERTA_DE_CURSO"]).ToString("0.############").Split(',')[1].Length > 0))
              {
                return "O Oferta_de_curso deve ser um valor inteiro com 10 dígitos no máximo.";
              }
            }

            if (dr["FACULDADE"] == null || string.IsNullOrEmpty(dr["FACULDADE"].ToString()))
            {
              return "Favor informar o Faculdade.";
            }

            if (dr["FACULDADE"] != null && !string.IsNullOrEmpty(dr["FACULDADE"].ToString()))
            {
              if (dr["FACULDADE"].ToString().Length > 20)
              {
                return "O Faculdade deve possuir no máximo 20 caracteres.";
              }
            }

            if (dr["OPCAO"] == null || string.IsNullOrEmpty(dr["OPCAO"].ToString()))
            {
              return "Favor informar o Opcao.";
            }

            if (dr["OPCAO"] != null && !string.IsNullOrEmpty(dr["OPCAO"].ToString()))
            {
              if ((Convert.ToDecimal(dr["OPCAO"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["OPCAO"]).ToString("0.############").Split(',')[0].Length > 10) || (Convert.ToDecimal(dr["OPCAO"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["OPCAO"]).ToString("0.############").Split(',')[1].Length > 0))
              {
                return "O Opcao deve ser um valor inteiro com 10 dígitos no máximo.";
              }
            }

            if (dr["DISCIPLINA"] != null && !string.IsNullOrEmpty(dr["DISCIPLINA"].ToString()))
            {
              if (dr["DISCIPLINA"].ToString().Length > 20)
              {
                return "O Disciplina deve possuir no máximo 20 caracteres.";
              }
            }

            if (dr["TURMA"] != null && !string.IsNullOrEmpty(dr["TURMA"].ToString()))
            {
              if (dr["TURMA"].ToString().Length > 50)
              {
                return "O Turma deve possuir no máximo 50 caracteres.";
              }
            }

            if (dr["ANO"] != null && !string.IsNullOrEmpty(dr["ANO"].ToString()))
            {
              if ((Convert.ToDecimal(dr["ANO"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ANO"]).ToString("0.############").Split(',')[0].Length > 4) || (Convert.ToDecimal(dr["ANO"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ANO"]).ToString("0.############").Split(',')[1].Length > 0))
              {
                return "O Ano deve ser um valor inteiro com 4 dígitos no máximo.";
              }
            }

            if (dr["SEMESTRE"] != null && !string.IsNullOrEmpty(dr["SEMESTRE"].ToString()))
            {
              if ((Convert.ToDecimal(dr["SEMESTRE"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["SEMESTRE"]).ToString("0.############").Split(',')[0].Length > 2) || (Convert.ToDecimal(dr["SEMESTRE"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["SEMESTRE"]).ToString("0.############").Split(',')[1].Length > 0))
              {
                return "O Semestre deve ser um valor inteiro com 2 dígitos no máximo.";
              }
            }

            if (dr["HORARIO_DESCRICAO"] != null && !string.IsNullOrEmpty(dr["HORARIO_DESCRICAO"].ToString()))
            {
              if (dr["HORARIO_DESCRICAO"].ToString().Length > 100)
              {
                return "O Horario_descricao deve possuir no máximo 100 caracteres.";
              }
            }
      }
      return "";
    }

