      if(result.Count == 0)
        if(tabPrincipal)
          result.AddRange(toLower
                          ? new string[] { "id_opcoes_p_seletivo", "oferta_de_curso", "concurso", "candidato", 
                                           "ordem" }
                          : new string[] { "ID_OPCOES_P_SELETIVO", "OFERTA_DE_CURSO", "CONCURSO", "CANDIDATO", 
                                           "ORDEM" });
        else
