        if(tabPrincipal)
          result.AddRange(toLower
                          ? new string[] { "pessoa", "publicacao" }
                          : new string[] { "PESSOA", "PUBLICACAO" });
        else
          result.AddRange(toLower
                          ? new string[] { "pessoa", "publicacao" }
                          : new string[] { "PESSOA", "PUBLICACAO" });

      return result;
    }


