    public string ValidaCampos(DataRow dr)
    {
      if (dr != null)
      {

            if (dr["DISCIPLINA"] == null || string.IsNullOrEmpty(dr["DISCIPLINA"].ToString()))
            {
              return "Favor informar o Disciplina.";
            }

            if (dr["DISCIPLINA"] != null && !string.IsNullOrEmpty(dr["DISCIPLINA"].ToString()))
            {
              if (dr["DISCIPLINA"].ToString().Length > 20)
              {
                return "O Disciplina deve possuir no máximo 20 caracteres.";
              }
            }

            if (dr["AULA"] == null || string.IsNullOrEmpty(dr["AULA"].ToString()))
            {
              return "Favor informar o Aula.";
            }

            if (dr["AULA"] != null && !string.IsNullOrEmpty(dr["AULA"].ToString()))
            {
              if (dr["AULA"].ToString().Length > 20)
              {
                return "O Aula deve possuir no máximo 20 caracteres.";
              }
            }

            if (dr["ASSUNTO_ATIVIDADES"] == null || string.IsNullOrEmpty(dr["ASSUNTO_ATIVIDADES"].ToString()))
            {
              return "Favor informar o Assunto_atividades.";
            }

            if (dr["ASSUNTO_ATIVIDADES"] != null && !string.IsNullOrEmpty(dr["ASSUNTO_ATIVIDADES"].ToString()))
            {
              if (dr["ASSUNTO_ATIVIDADES"].ToString().Length > 2000)
              {
                return "O Assunto_atividades deve possuir no máximo 2000 caracteres.";
              }
            }

            if (dr["BIBLIOGRAFIA"] != null && !string.IsNullOrEmpty(dr["BIBLIOGRAFIA"].ToString()))
            {
              if (dr["BIBLIOGRAFIA"].ToString().Length > 4000)
              {
                return "O Bibliografia deve possuir no máximo 4000 caracteres.";
              }
            }

            if (dr["OBSERVACOES"] != null && !string.IsNullOrEmpty(dr["OBSERVACOES"].ToString()))
            {
              if (dr["OBSERVACOES"].ToString().Length > 2000)
              {
                return "O Observacoes deve possuir no máximo 2000 caracteres.";
              }
            }

            if (dr["SUBDISCIPLINA"] != null && !string.IsNullOrEmpty(dr["SUBDISCIPLINA"].ToString()))
            {
              if (dr["SUBDISCIPLINA"].ToString().Length > 20)
              {
                return "O Subdisciplina deve possuir no máximo 20 caracteres.";
              }
            }

            if (dr["RECURSOS"] != null && !string.IsNullOrEmpty(dr["RECURSOS"].ToString()))
            {
              if (dr["RECURSOS"].ToString().Length > 2000)
              {
                return "O Recursos deve possuir no máximo 2000 caracteres.";
              }
            }

            if (dr["STAMP_ATUALIZACAO"] != null && dr["STAMP_ATUALIZACAO"].ToString() != "")
            {
              dr["STAMP_ATUALIZACAO"] = Convert.ToDateTime(dr["STAMP_ATUALIZACAO"]).ToString("dd/MM/yyyy HH:mm:ss");
            }
      }
      return "";
    }

