    /// <summary>
    /// Filtra o array de colunas retornando somente as colunas pertencentes ao DataTable.
    /// Devolve StringCollection para que seja possível utilizar o método Contains().
    /// </summary>
    /// <param name="toLower">As colunas serăo devolvidas em minúsculas</param>
    /// <param name="tabPrincipal">Somente colunas da tabela principal</param>
    private static StringCollection FilterColumns(string[] columns, bool toLower, bool tabPrincipal) {
      StringCollection result = new StringCollection();

      if(columns != null)
        foreach(string column in columns) {
          string lower = column.ToLower();
          if(lower == "disciplina") { result.Add(toLower ? "disciplina" : column); continue; }
          if(lower == "ementa_resumo") { result.Add(toLower ? "ementa_resumo" : column); continue; }
          if(lower == "objetivo") { result.Add(toLower ? "objetivo" : column); continue; }
          if(lower == "metodologia") { result.Add(toLower ? "metodologia" : column); continue; }
          if(lower == "criterio_aval") { result.Add(toLower ? "criterio_aval" : column); continue; }
          if(lower == "pode_alterar_turma") { result.Add(toLower ? "pode_alterar_turma" : column); continue; }
          if(!tabPrincipal) {
          }
        }

      if(result.Count == 0)
        if(tabPrincipal)
          result.AddRange(toLower
                          ? new string[] { "disciplina", "ementa_resumo", "objetivo", "metodologia", "criterio_aval", 
                                           "pode_alterar_turma" }
                          : new string[] { "DISCIPLINA", "EMENTA_RESUMO", "OBJETIVO", "METODOLOGIA", "CRITERIO_AVAL", 
                                           "PODE_ALTERAR_TURMA" });
        else
          result.AddRange(toLower
                          ? new string[] { "disciplina", "ementa_resumo", "objetivo", "metodologia", "criterio_aval", 
                                           "pode_alterar_turma" }
                          : new string[] { "DISCIPLINA", "EMENTA_RESUMO", "OBJETIVO", "METODOLOGIA", "CRITERIO_AVAL", 
                                           "PODE_ALTERAR_TURMA" });

      return result;
    }


