        da.UpdateCommand = CreateCommand(connection, CommandOperation.Update);
        da.DeleteCommand = CreateCommand(connection, CommandOperation.Delete);
      }



      Put(da, connection, dataRows);
    }

    public void ValidaConvEmptyStrToNull(ref DataRow dr)
    {
      if (dr != null)
      {
            if (dr["DISCIPLINA"] != null && string.IsNullOrEmpty(dr["DISCIPLINA"].ToString()))
              dr["DISCIPLINA"] = DBNull.Value;
            if (dr["EMENTA_RESUMO"] != null && string.IsNullOrEmpty(dr["EMENTA_RESUMO"].ToString()))
              dr["EMENTA_RESUMO"] = DBNull.Value;
            if (dr["OBJETIVO"] != null && string.IsNullOrEmpty(dr["OBJETIVO"].ToString()))
              dr["OBJETIVO"] = DBNull.Value;
            if (dr["METODOLOGIA"] != null && string.IsNullOrEmpty(dr["METODOLOGIA"].ToString()))
              dr["METODOLOGIA"] = DBNull.Value;
            if (dr["CRITERIO_AVAL"] != null && string.IsNullOrEmpty(dr["CRITERIO_AVAL"].ToString()))
              dr["CRITERIO_AVAL"] = DBNull.Value;
            if (dr["PODE_ALTERAR_TURMA"] != null && string.IsNullOrEmpty(dr["PODE_ALTERAR_TURMA"].ToString()))
              dr["PODE_ALTERAR_TURMA"] = DBNull.Value;
      }
    }

    public string ValidaCampos(DataRow dr)
    {
      if (dr != null)
      {

            if (dr["DISCIPLINA"] == null || string.IsNullOrEmpty(dr["DISCIPLINA"].ToString()))
            {
              return "Favor informar o Disciplina.";
            }

            if (dr["DISCIPLINA"] != null && !string.IsNullOrEmpty(dr["DISCIPLINA"].ToString()))
            {
              if (dr["DISCIPLINA"].ToString().Length > 20)
              {
                return "O Disciplina deve possuir no máximo 20 caracteres.";
              }
            }

            if (dr["EMENTA_RESUMO"] != null && !string.IsNullOrEmpty(dr["EMENTA_RESUMO"].ToString()))
            {
              if (dr["EMENTA_RESUMO"].ToString().Length > 2000)
              {
                return "O Ementa_resumo deve possuir no máximo 2000 caracteres.";
              }
            }

            if (dr["OBJETIVO"] != null && !string.IsNullOrEmpty(dr["OBJETIVO"].ToString()))
            {
              if (dr["OBJETIVO"].ToString().Length > 2000)
              {
                return "O Objetivo deve possuir no máximo 2000 caracteres.";
              }
            }

            if (dr["METODOLOGIA"] != null && !string.IsNullOrEmpty(dr["METODOLOGIA"].ToString()))
            {
              if (dr["METODOLOGIA"].ToString().Length > 2000)
              {
                return "O Metodologia deve possuir no máximo 2000 caracteres.";
              }
            }

            if (dr["CRITERIO_AVAL"] != null && !string.IsNullOrEmpty(dr["CRITERIO_AVAL"].ToString()))
            {
              if (dr["CRITERIO_AVAL"].ToString().Length > 2000)
              {
                return "O Criterio_aval deve possuir no máximo 2000 caracteres.";
              }
            }

            if (dr["PODE_ALTERAR_TURMA"] == null || string.IsNullOrEmpty(dr["PODE_ALTERAR_TURMA"].ToString()))
            {
              return "Favor informar o Pode_alterar_turma.";
            }

            if (dr["PODE_ALTERAR_TURMA"] != null && !string.IsNullOrEmpty(dr["PODE_ALTERAR_TURMA"].ToString()))
            {
              if (dr["PODE_ALTERAR_TURMA"].ToString().Length > 1)
              {
                return "O Pode_alterar_turma deve possuir no máximo 1 caractere.";
              }

              if (dr["PODE_ALTERAR_TURMA"] != null && !string.IsNullOrEmpty(dr["PODE_ALTERAR_TURMA"].ToString()))
              {
                List<object> lstPODE_ALTERAR_TURMA = new List<object>(new object[]{"N", "S"});
                if(!lstPODE_ALTERAR_TURMA.Contains(dr["PODE_ALTERAR_TURMA"].ToString()))
                {
                  return "Os valores permitidos para o Pode_alterar_turma săo ''N'' ou ''S''.";
                }
              }
            }
      }
      return "";
    }

    protected override string PreInsert(DataRow row, TConnectionWritable connection)
    {
      ValidaConvEmptyStrToNull(ref row);
      return ValidaCampos(row);
    }

    protected override string PreUpdate(DataRow row, TConnectionWritable connection)
    {
      ValidaConvEmptyStrToNull(ref row);
      return ValidaCampos(row);
    }

