    public string ValidaCampos(DataRow dr)
    {
      if (dr != null)
      {

            if (dr["OFERTA_DE_CURSO"] == null || string.IsNullOrEmpty(dr["OFERTA_DE_CURSO"].ToString()))
            {
              return "Favor informar o Oferta_de_curso.";
            }

            if (dr["OFERTA_DE_CURSO"] != null && !string.IsNullOrEmpty(dr["OFERTA_DE_CURSO"].ToString()))
            {
              if ((Convert.ToDecimal(dr["OFERTA_DE_CURSO"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["OFERTA_DE_CURSO"]).ToString("0.############").Split(',')[0].Length > 10) || (Convert.ToDecimal(dr["OFERTA_DE_CURSO"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["OFERTA_DE_CURSO"]).ToString("0.############").Split(',')[1].Length > 0))
              {
                return "O Oferta_de_curso deve ser um valor inteiro com 10 dígitos no máximo.";
              }
            }

            if (dr["RESP"] == null || string.IsNullOrEmpty(dr["RESP"].ToString()))
            {
              return "Favor informar o Resp.";
            }

            if (dr["RESP"] != null && !string.IsNullOrEmpty(dr["RESP"].ToString()))
            {
              if (dr["RESP"].ToString().Length > 20)
              {
                return "O Resp deve possuir no máximo 20 caracteres.";
              }
            }

            if (dr["LANC_DEB"] != null && !string.IsNullOrEmpty(dr["LANC_DEB"].ToString()))
            {
              if ((Convert.ToDecimal(dr["LANC_DEB"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["LANC_DEB"]).ToString("0.############").Split(',')[0].Length > 10) || (Convert.ToDecimal(dr["LANC_DEB"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["LANC_DEB"]).ToString("0.############").Split(',')[1].Length > 0))
              {
                return "O Lanc_deb deve ser um valor inteiro com 10 dígitos no máximo.";
              }
            }

            if (dr["ANO"] != null && !string.IsNullOrEmpty(dr["ANO"].ToString()))
            {
              if ((Convert.ToDecimal(dr["ANO"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ANO"]).ToString("0.############").Split(',')[0].Length > 4) || (Convert.ToDecimal(dr["ANO"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ANO"]).ToString("0.############").Split(',')[1].Length > 0))
              {
                return "O Ano deve ser um valor inteiro com 4 dígitos no máximo.";
              }
            }

            if (dr["PERIODO"] != null && !string.IsNullOrEmpty(dr["PERIODO"].ToString()))
            {
              if ((Convert.ToDecimal(dr["PERIODO"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["PERIODO"]).ToString("0.############").Split(',')[0].Length > 2) || (Convert.ToDecimal(dr["PERIODO"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["PERIODO"]).ToString("0.############").Split(',')[1].Length > 0))
              {
                return "O Periodo deve ser um valor inteiro com 2 dígitos no máximo.";
              }
            }

            if (dr["ALUNO"] == null || string.IsNullOrEmpty(dr["ALUNO"].ToString()))
            {
              return "Favor informar o Aluno.";
            }

            if (dr["ALUNO"] != null && !string.IsNullOrEmpty(dr["ALUNO"].ToString()))
            {
              if (dr["ALUNO"].ToString().Length > 20)
              {
                return "O Aluno deve possuir no máximo 20 caracteres.";
              }
            }

            if (dr["PLANOPAG"] != null && !string.IsNullOrEmpty(dr["PLANOPAG"].ToString()))
            {
              if (dr["PLANOPAG"].ToString().Length > 20)
              {
                return "O Planopag deve possuir no máximo 20 caracteres.";
              }
            }

            if (dr["ANO_INICIAL"] != null && !string.IsNullOrEmpty(dr["ANO_INICIAL"].ToString()))
            {
              if ((Convert.ToDecimal(dr["ANO_INICIAL"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ANO_INICIAL"]).ToString("0.############").Split(',')[0].Length > 4) || (Convert.ToDecimal(dr["ANO_INICIAL"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ANO_INICIAL"]).ToString("0.############").Split(',')[1].Length > 0))
              {
                return "O Ano_inicial deve ser um valor inteiro com 4 dígitos no máximo.";
              }
            }

            if (dr["MES_INICIAL"] != null && !string.IsNullOrEmpty(dr["MES_INICIAL"].ToString()))
            {
              if ((Convert.ToDecimal(dr["MES_INICIAL"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["MES_INICIAL"]).ToString("0.############").Split(',')[0].Length > 3) || (Convert.ToDecimal(dr["MES_INICIAL"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["MES_INICIAL"]).ToString("0.############").Split(',')[1].Length > 0))
              {
                return "O Mes_inicial deve ser um valor inteiro com 3 dígitos no máximo.";
              }
            }

            if (dr["DIA_VENCIMENTO"] != null && !string.IsNullOrEmpty(dr["DIA_VENCIMENTO"].ToString()))
            {
              if ((Convert.ToDecimal(dr["DIA_VENCIMENTO"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["DIA_VENCIMENTO"]).ToString("0.############").Split(',')[0].Length > 3) || (Convert.ToDecimal(dr["DIA_VENCIMENTO"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["DIA_VENCIMENTO"]).ToString("0.############").Split(',')[1].Length > 0))
              {
                return "O Dia_vencimento deve ser um valor inteiro com 3 dígitos no máximo.";
              }
            }

            if (dr["DESC_PERC_VALOR"] != null && !string.IsNullOrEmpty(dr["DESC_PERC_VALOR"].ToString()))
            {
              if (dr["DESC_PERC_VALOR"].ToString().Length > 15)
              {
                return "O Desc_perc_valor deve possuir no máximo 15 caracteres.";
              }
            }

            if (dr["DESCONTO"] != null && !string.IsNullOrEmpty(dr["DESCONTO"].ToString()))
            {
              if ((Convert.ToDecimal(dr["DESCONTO"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["DESCONTO"]).ToString("0.############").Split(',')[0].Length > 8) || (Convert.ToDecimal(dr["DESCONTO"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["DESCONTO"]).ToString("0.############").Split(',')[1].Length > 6))
              {
                return "O Desconto deve ser um valor numérico com, no máximo, 8 dígitos na parte inteira e 6 casas decimal.";
