      if(scColumns.Contains("num_parcelas")) list.Add("ly_planopgtoperiodo_aux.num_parcelas");
      if(scColumns.Contains("percent_divida_aluno")) list.Add("ly_planopgtoperiodo_aux.percent_divida_aluno");
      if(scColumns.Contains("dt_ult_alt")) list.Add("ly_planopgtoperiodo_aux.dt_ult_alt");
      if(scColumns.Contains("aplicabolsa")) list.Add("ly_planopgtoperiodo_aux.aplicabolsa");
      if(scColumns.Contains("aparece_extrato_aluno")) list.Add("ly_planopgtoperiodo_aux.aparece_extrato_aluno");
