      if(scColumns.Contains("dv_agencia")) list.Add("ly_planopgtoperiodo_aux.dv_agencia");
      if(scColumns.Contains("dv_conta")) list.Add("ly_planopgtoperiodo_aux.dv_conta");
      if(scColumns.Contains("dv_agencia_conta")) list.Add("ly_planopgtoperiodo_aux.dv_agencia_conta");
