    /// <summary>
    /// Filtra o array de colunas retornando somente as colunas pertencentes ao DataTable.
    /// Devolve StringCollection para que seja possível utilizar o método Contains().
    /// </summary>
    /// <param name="toLower">As colunas serăo devolvidas em minúsculas</param>
    /// <param name="tabPrincipal">Somente colunas da tabela principal</param>
    private static StringCollection FilterColumns(string[] columns, bool toLower, bool tabPrincipal) {
      StringCollection result = new StringCollection();

      if(columns != null)
        foreach(string column in columns) {
          string lower = column.ToLower();
          if(lower == "oferta_de_curso") { result.Add(toLower ? "oferta_de_curso" : column); continue; }
          if(lower == "plano") { result.Add(toLower ? "plano" : column); continue; }
          if(lower == "planopag") { result.Add(toLower ? "planopag" : column); continue; }
          if(lower == "descricao") { result.Add(toLower ? "descricao" : column); continue; }
          if(lower == "mes_inicial") { result.Add(toLower ? "mes_inicial" : column); continue; }
          if(lower == "num_parcelas") { result.Add(toLower ? "num_parcelas" : column); continue; }
          if(lower == "tipo_desc") { result.Add(toLower ? "tipo_desc" : column); continue; }
          if(lower == "desconto") { result.Add(toLower ? "desconto" : column); continue; }
          if(lower == "data_de_vencimento") { result.Add(toLower ? "data_de_vencimento" : column); continue; }
          if(lower == "forma_pagamento") { result.Add(toLower ? "forma_pagamento" : column); continue; }
          if(lower == "num_parcelas_inscr") { result.Add(toLower ? "num_parcelas_inscr" : column); continue; }
          if(lower == "n_dias_venc_bol") { result.Add(toLower ? "n_dias_venc_bol" : column); continue; }
          if(lower == "valor_estimado") { result.Add(toLower ? "valor_estimado" : column); continue; }
          if(!tabPrincipal) {
          }
        }

      if(result.Count == 0)
        if(tabPrincipal)
          result.AddRange(toLower
                          ? new string[] { "oferta_de_curso", "plano", "planopag", "descricao", "mes_inicial", 
                                           "num_parcelas", "tipo_desc", "desconto", "data_de_vencimento", "forma_pagamento", 
                                           "num_parcelas_inscr", "n_dias_venc_bol", "valor_estimado" }
                          : new string[] { "OFERTA_DE_CURSO", "PLANO", "PLANOPAG", "DESCRICAO", "MES_INICIAL", 
                                           "NUM_PARCELAS", "TIPO_DESC", "DESCONTO", "DATA_DE_VENCIMENTO", "FORMA_PAGAMENTO", 
                                           "NUM_PARCELAS_INSCR", "N_DIAS_VENC_BOL", "VALOR_ESTIMADO" });
        else
          result.AddRange(toLower
                          ? new string[] { "oferta_de_curso", "plano", "planopag", "descricao", "mes_inicial", 
                                           "num_parcelas", "tipo_desc", "desconto", "data_de_vencimento", "forma_pagamento", 
                                           "num_parcelas_inscr", "n_dias_venc_bol", "valor_estimado" }
                          : new string[] { "OFERTA_DE_CURSO", "PLANO", "PLANOPAG", "DESCRICAO", "MES_INICIAL", 
                                           "NUM_PARCELAS", "TIPO_DESC", "DESCONTO", "DATA_DE_VENCIMENTO", "FORMA_PAGAMENTO", 
                                           "NUM_PARCELAS_INSCR", "N_DIAS_VENC_BOL", "VALOR_ESTIMADO" });

      return result;
    }


