    public string ValidaCampos(DataRow dr)
    {
      if (dr != null)
      {

            if (dr["OFERTA_DE_CURSO"] == null || string.IsNullOrEmpty(dr["OFERTA_DE_CURSO"].ToString()))
            {
              return "Favor informar o Oferta_de_curso.";
            }

            if (dr["OFERTA_DE_CURSO"] != null && !string.IsNullOrEmpty(dr["OFERTA_DE_CURSO"].ToString()))
            {
              if ((Convert.ToDecimal(dr["OFERTA_DE_CURSO"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["OFERTA_DE_CURSO"]).ToString("0.############").Split(',')[0].Length > 10) || (Convert.ToDecimal(dr["OFERTA_DE_CURSO"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["OFERTA_DE_CURSO"]).ToString("0.############").Split(',')[1].Length > 0))
              {
                return "O Oferta_de_curso deve ser um valor inteiro com 10 dígitos no máximo.";
              }
            }

            if (dr["PLANO"] == null || string.IsNullOrEmpty(dr["PLANO"].ToString()))
            {
              return "Favor informar o Plano.";
            }

            if (dr["PLANO"] != null && !string.IsNullOrEmpty(dr["PLANO"].ToString()))
            {
              if (dr["PLANO"].ToString().Length > 20)
              {
                return "O Plano deve possuir no máximo 20 caracteres.";
              }
            }

            if (dr["PLANOPAG"] != null && !string.IsNullOrEmpty(dr["PLANOPAG"].ToString()))
            {
              if (dr["PLANOPAG"].ToString().Length > 20)
              {
                return "O Planopag deve possuir no máximo 20 caracteres.";
              }
            }

            if (dr["DESCRICAO"] == null || string.IsNullOrEmpty(dr["DESCRICAO"].ToString()))
            {
              return "Favor informar o Descricao.";
            }

            if (dr["DESCRICAO"] != null && !string.IsNullOrEmpty(dr["DESCRICAO"].ToString()))
            {
              if (dr["DESCRICAO"].ToString().Length > 2000)
              {
                return "O Descricao deve possuir no máximo 2000 caracteres.";
              }
            }

            if (dr["MES_INICIAL"] != null && !string.IsNullOrEmpty(dr["MES_INICIAL"].ToString()))
            {
              if ((Convert.ToDecimal(dr["MES_INICIAL"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["MES_INICIAL"]).ToString("0.############").Split(',')[0].Length > 3) || (Convert.ToDecimal(dr["MES_INICIAL"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["MES_INICIAL"]).ToString("0.############").Split(',')[1].Length > 0))
              {
                return "O Mes_inicial deve ser um valor inteiro com 3 dígitos no máximo.";
              }
            }

            if (dr["NUM_PARCELAS"] != null && !string.IsNullOrEmpty(dr["NUM_PARCELAS"].ToString()))
            {
              if ((Convert.ToDecimal(dr["NUM_PARCELAS"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["NUM_PARCELAS"]).ToString("0.############").Split(',')[0].Length > 3) || (Convert.ToDecimal(dr["NUM_PARCELAS"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["NUM_PARCELAS"]).ToString("0.############").Split(',')[1].Length > 0))
              {
                return "O Num_parcelas deve ser um valor inteiro com 3 dígitos no máximo.";
              }
            }

            if (dr["TIPO_DESC"] != null && !string.IsNullOrEmpty(dr["TIPO_DESC"].ToString()))
            {
              if (dr["TIPO_DESC"].ToString().Length > 15)
              {
                return "O Tipo_desc deve possuir no máximo 15 caracteres.";
              }
            }

            if (dr["DESCONTO"] != null && !string.IsNullOrEmpty(dr["DESCONTO"].ToString()))
            {
              if ((Convert.ToDecimal(dr["DESCONTO"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["DESCONTO"]).ToString("0.############").Split(',')[0].Length > 8) || (Convert.ToDecimal(dr["DESCONTO"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["DESCONTO"]).ToString("0.############").Split(',')[1].Length > 2))
              {
                return "O Desconto deve ser um valor numérico com, no máximo, 8 dígitos na parte inteira e 2 casas decimal.";
              }
            }

            if (dr["DATA_DE_VENCIMENTO"] != null && dr["DATA_DE_VENCIMENTO"].ToString() != "")
            {
              dr["DATA_DE_VENCIMENTO"] = Convert.ToDateTime(dr["DATA_DE_VENCIMENTO"]).ToString("dd/MM/yyyy HH:mm:ss");
            }

            if (dr["FORMA_PAGAMENTO"] != null && !string.IsNullOrEmpty(dr["FORMA_PAGAMENTO"].ToString()))
            {
              if (dr["FORMA_PAGAMENTO"].ToString().Length > 100)
              {
                return "O Forma_pagamento deve possuir no máximo 100 caracteres.";
              }

              if (dr["FORMA_PAGAMENTO"] != null && !string.IsNullOrEmpty(dr["FORMA_PAGAMENTO"].ToString()))
              {
                List<object> lstFORMA_PAGAMENTO = new List<object>(new object[]{"Cartao", "Boleto"});
                if(!lstFORMA_PAGAMENTO.Contains(dr["FORMA_PAGAMENTO"].ToString()))
                {
                  return "Os valores permitidos para o Forma_pagamento săo ''Cartao'' ou ''Boleto''.";
                }
              }
            }

            if (dr["NUM_PARCELAS_INSCR"] != null && !string.IsNullOrEmpty(dr["NUM_PARCELAS_INSCR"].ToString()))
            {
              if ((Convert.ToDecimal(dr["NUM_PARCELAS_INSCR"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["NUM_PARCELAS_INSCR"]).ToString("0.############").Split(',')[0].Length > 3) || (Convert.ToDecimal(dr["NUM_PARCELAS_INSCR"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["NUM_PARCELAS_INSCR"]).ToString("0.############").Split(',')[1].Length > 0))
              {
                return "O Num_parcelas_inscr deve ser um valor inteiro com 3 dígitos no máximo.";
              }
            }

            if (dr["N_DIAS_VENC_BOL"] != null && !string.IsNullOrEmpty(dr["N_DIAS_VENC_BOL"].ToString()))
            {
              if ((Convert.ToDecimal(dr["N_DIAS_VENC_BOL"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["N_DIAS_VENC_BOL"]).ToString("0.############").Split(',')[0].Length > 10) || (Convert.ToDecimal(dr["N_DIAS_VENC_BOL"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["N_DIAS_VENC_BOL"]).ToString("0.############").Split(',')[1].Length > 0))
              {
                return "O N_dias_venc_bol deve ser um valor inteiro com 10 dígitos no máximo.";
              }
            }

            if (dr["VALOR_ESTIMADO"] != null && !string.IsNullOrEmpty(dr["VALOR_ESTIMADO"].ToString()))
            {
              if ((Convert.ToDecimal(dr["VALOR_ESTIMADO"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["VALOR_ESTIMADO"]).ToString("0.############").Split(',')[0].Length > 8) || (Convert.ToDecimal(dr["VALOR_ESTIMADO"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["VALOR_ESTIMADO"]).ToString("0.############").Split(',')[1].Length > 2))
              {
                return "O Valor_estimado deve ser um valor numérico com, no máximo, 8 dígitos na parte inteira e 2 casas decimal.";
              }
            }
      }
      return "";
    }

