          if(lower == "rotulo") { result.Add(toLower ? "rotulo" : column); continue; }
          if(lower == "descricao") { result.Add(toLower ? "descricao" : column); continue; }
          if(!tabPrincipal) {
          }
        }

      if(result.Count == 0)
        if(tabPrincipal)
          result.AddRange(toLower
                          ? new string[] { "id_prematr_instr", "oferta_de_curso", "ordem", "rotulo", "descricao" }
                          : new string[] { "ID_PREMATR_INSTR", "OFERTA_DE_CURSO", "ORDEM", "ROTULO", "DESCRICAO" });
        else
          result.AddRange(toLower
                          ? new string[] { "id_prematr_instr", "oferta_de_curso", "ordem", "rotulo", "descricao" }
                          : new string[] { "ID_PREMATR_INSTR", "OFERTA_DE_CURSO", "ORDEM", "ROTULO", "DESCRICAO" });

      return result;
    }


