        if(tabPrincipal)
          result.AddRange(toLower
                          ? new string[] { "id_prospecto", "login", "dt_insercao", "pessoa", "dt_ultimo_acesso", 
                                           "recebe_informacao", "senha" }
                          : new string[] { "ID_PROSPECTO", "LOGIN", "DT_INSERCAO", "PESSOA", "DT_ULTIMO_ACESSO", 
