    public override sealed int Get(TConnection connection,
                                   string[] columns,
                                   string where, DbObject[] whereValues,
                                   string order,
                                   int startRecord,
                                   int maxRecords,
                                   bool createPrimaryKey,
                                   bool getDeletedRecords,
                                   bool rowCountOnly) {
      if(where == null) throw new ArgumentNullException("where");
      if(order == null) throw new ArgumentNullException("order");
      TConnection cn = connection != null ? connection : Config.CreateConnection();
      bool sqlServer = cn.Rdbms == Rdbms.SQLServer;
      where = where.Trim();

      int count;

      StringCollection scColumns = FilterColumns(columns, true, false);

      #region Build Select
      ArrayList list = new ArrayList();
      list.AddRange(new string[] {
        "ly_sub_grupo_oferta.id_sub_grupo_oferta"
      });
      if(scColumns.Contains("grupo_oferta")) list.Add("ly_sub_grupo_oferta.grupo_oferta");
      if(scColumns.Contains("sub_grupo")) list.Add("ly_sub_grupo_oferta.sub_grupo");
      if(scColumns.Contains("descricao")) list.Add("ly_sub_grupo_oferta.descricao");
      if(scColumns.Contains("msg_aprovacao")) list.Add("ly_sub_grupo_oferta.msg_aprovacao");
      if(scColumns.Contains("msg_desclassif_nota")) list.Add("ly_sub_grupo_oferta.msg_desclassif_nota");
      if(scColumns.Contains("msg_desclassif_falta")) list.Add("ly_sub_grupo_oferta.msg_desclassif_falta");
      if(scColumns.Contains("msg_listaespera")) list.Add("ly_sub_grupo_oferta.msg_listaespera");
      if(scColumns.Contains("msg_matricula")) list.Add("ly_sub_grupo_oferta.msg_matricula");
      if(scColumns.Contains("link_matricula")) list.Add("ly_sub_grupo_oferta.link_matricula");
      if(scColumns.Contains("exige_senha")) list.Add("ly_sub_grupo_oferta.exige_senha");
      string select,columnList,orderby;
      if (rowCountOnly)
      {
        columnList = "count(*)";
        orderby = "";
      }
      else
      {
        columnList = StrLib.EnumerableToStr(list, ", ");
        orderby = (order.Trim().Length == 0 ? string.Empty : " ORDER BY " + order);
      }
      select =
        "SELECT " + columnList + " " +
          "FROM ly_sub_grupo_oferta " +
          (where.Length == 0 ? string.Empty : " WHERE " + where) +
          orderby;

      #endregion
      if (rowCountOnly)
      {
        #region RowCountOnly
        using(TCommand cm = cn.CreateCommand(select, whereValues)) 
        {
          try 
          {
            count = (int)(decimal)cm.ExecuteScalar();
          }
          catch(Exception exc)
          {
            throw new Exception(exc.Message + " " +
              "Select statement: [" + select + "], " +
              "Parameters: [" + StrLib.EnumerableToStr(whereValues) + "]");
          }
        }
        #endregion
      }
      else
      {
        #region Fill Datatable
        using(TCommand cm = cn.CreateCommand(select, whereValues)) {
          TDataAdapter da = new TDataAdapter(cm);
          try {
            DataSet ds = BaseDataSet;
            bool fakeds = false;
            if(ds == null) {
              fakeds = true;
              ds = new DataSet();
              ds.Tables.Add(this);
            }
            count = da.Fill(ds, startRecord, maxRecords, "ly_sub_grupo_oferta");
            if(fakeds) ds.Tables.Remove(this);
          }
          catch(Exception exc) {
            throw new Exception(exc.Message + " " +
                                "Select statement: [" + select + "], " +
                                "Parameters: [" + StrLib.EnumerableToStr(whereValues) + "]");
          }
        }

        if(createPrimaryKey) SetPrimaryKey();

        // Cria os nomes (caption) nas colunas da tabela do DataSet
        // de acordo com o idioma informado no construtor da classe.
        foreach(DataColumn dataColumn in Columns) {
          TDataColumn c = dataColumn as TDataColumn;
          if(c != null && scColumns.Contains(c.ColumnName.ToLower()))
            c.ReadOnly = c.IsAux;
        }
        #endregion
      }

      return count;
    }

