          string lower = column.ToLower();
          if(lower == "tipo_nivel_idioma") { result.Add(toLower ? "tipo_nivel_idioma" : column); continue; }
          if(lower == "descricao") { result.Add(toLower ? "descricao" : column); continue; }
          if(!tabPrincipal) {
          }
        }

      if(result.Count == 0)
        if(tabPrincipal)
          result.AddRange(toLower
                          ? new string[] { "tipo_nivel_idioma", "descricao" }
                          : new string[] { "TIPO_NIVEL_IDIOMA", "DESCRICAO" });
        else
          result.AddRange(toLower
                          ? new string[] { "tipo_nivel_idioma", "descricao" }
                          : new string[] { "TIPO_NIVEL_IDIOMA", "DESCRICAO" });

      return result;
    }


